import "dotenv/config";
import { type Abi } from "viem";

function requireEnv(name: string): string {
  const val = process.env[name];
  if (!val) throw new Error(`Missing env var: ${name}`);
  return val;
}

function optionalEnv(name: string, fallback: string): string {
  return process.env[name] || fallback;
}

export const config = {
  sepoliaRpcUrl: requireEnv("SEPOLIA_RPC_URL"),
  deployerKey: requireEnv("DEPLOYER_PRIVATE_KEY") as `0x${string}`,
  contributorKey: requireEnv("CONTRIBUTOR_PRIVATE_KEY") as `0x${string}`,
  borrowerKey: requireEnv("BORROWER_PRIVATE_KEY") as `0x${string}`,
  memoryLendingAddress: requireEnv("MEMORY_LENDING_ADDRESS") as `0x${string}`,
  identityRegistry: optionalEnv(
    "IDENTITY_REGISTRY",
    "0x8004A169FB4a3325136EB29fA0ceB6D2e539a432"
  ) as `0x${string}`,
  reputationRegistry: optionalEnv(
    "REPUTATION_REGISTRY",
    "0x8004BAa17C55a88189AE136b182e5fdA19dE9b63"
  ) as `0x${string}`,
  contributorAgentId: BigInt(optionalEnv("CONTRIBUTOR_AGENT_ID", "0")),
  borrowerAgentId: BigInt(optionalEnv("BORROWER_AGENT_ID", "0")),
  anthropicApiKey: optionalEnv("ANTHROPIC_API_KEY", ""),
  fragmentServerPort: parseInt(optionalEnv("FRAGMENT_SERVER_PORT", "3000")),
};

export const MEMORY_LENDING_ABI = [
  {
    type: "function",
    name: "publishFragment",
    inputs: [
      { name: "contributorAgentId", type: "uint256" },
      { name: "contentHash", type: "bytes32" },
      { name: "contentURI", type: "string" },
      { name: "domain", type: "string" },
      { name: "priceWei", type: "uint256" },
    ],
    outputs: [{ name: "fragmentId", type: "uint256" }],
    stateMutability: "nonpayable",
  },
  {
    type: "function",
    name: "borrowFragment",
    inputs: [
      { name: "fragmentId", type: "uint256" },
      { name: "borrowerAgentId", type: "uint256" },
    ],
    outputs: [],
    stateMutability: "payable",
  },
  {
    type: "function",
    name: "deactivateFragment",
    inputs: [{ name: "fragmentId", type: "uint256" }],
    outputs: [],
    stateMutability: "nonpayable",
  },
  {
    type: "function",
    name: "getFragment",
    inputs: [{ name: "fragmentId", type: "uint256" }],
    outputs: [
      {
        name: "",
        type: "tuple",
        components: [
          { name: "contributorAgentId", type: "uint256" },
          { name: "contributor", type: "address" },
          { name: "contentHash", type: "bytes32" },
          { name: "contentURI", type: "string" },
          { name: "domain", type: "string" },
          { name: "priceWei", type: "uint256" },
          { name: "createdAt", type: "uint256" },
          { name: "active", type: "bool" },
        ],
      },
    ],
    stateMutability: "view",
  },
  {
    type: "function",
    name: "nextFragmentId",
    inputs: [],
    outputs: [{ name: "", type: "uint256" }],
    stateMutability: "view",
  },
  {
    type: "event",
    name: "FragmentPublished",
    inputs: [
      { name: "fragmentId", type: "uint256", indexed: true },
      { name: "contributorAgentId", type: "uint256", indexed: true },
      { name: "contributor", type: "address", indexed: false },
      { name: "contentHash", type: "bytes32", indexed: false },
      { name: "domain", type: "string", indexed: false },
      { name: "priceWei", type: "uint256", indexed: false },
    ],
  },
  {
    type: "event",
    name: "FragmentBorrowed",
    inputs: [
      { name: "fragmentId", type: "uint256", indexed: true },
      { name: "borrowerAgentId", type: "uint256", indexed: true },
      { name: "contributorAgentId", type: "uint256", indexed: true },
      { name: "pricePaid", type: "uint256", indexed: false },
      { name: "contentHash", type: "bytes32", indexed: false },
    ],
  },
] as const satisfies Abi;

export const REPUTATION_REGISTRY_ABI = [
  {
    type: "function",
    name: "giveFeedback",
    inputs: [
      { name: "agentId", type: "uint256" },
      { name: "value", type: "int128" },
      { name: "valueDecimals", type: "uint8" },
      { name: "tag1", type: "string" },
      { name: "tag2", type: "string" },
      { name: "endpoint", type: "string" },
      { name: "feedbackURI", type: "string" },
      { name: "feedbackHash", type: "bytes32" },
    ],
    outputs: [],
    stateMutability: "nonpayable",
  },
] as const satisfies Abi;

import { type PublicClient, type WalletClient } from "viem";
import { config, REPUTATION_REGISTRY_ABI } from "./config.js";

/// Check if an agent ID is registered in the ERC-8004 Identity Registry
export async function isAgentRegistered(
  publicClient: PublicClient,
  agentId: bigint
): Promise<boolean> {
  try {
    const owner = await publicClient.readContract({
      address: config.identityRegistry,
      abi: [
        {
          type: "function",
          name: "ownerOf",
          inputs: [{ name: "tokenId", type: "uint256" }],
          outputs: [{ name: "", type: "address" }],
          stateMutability: "view",
        },
      ] as const,
      functionName: "ownerOf",
      args: [agentId],
    });
    return owner !== "0x0000000000000000000000000000000000000000";
  } catch {
    return false;
  }
}

/// Submit feedback to the ERC-8004 Reputation Registry
/// Score is 1-10, stored as value with 0 decimals.
/// tag1 = "memory-lend", tag2 = domain tag (e.g. "aquaculture").
export async function giveFeedback(
  walletClient: WalletClient,
  agentId: bigint,
  score: number,
  tag1: string,
  tag2: string,
  feedbackURI: string,
  feedbackHash: `0x${string}`
): Promise<`0x${string}`> {
  if (!walletClient.account) throw new Error("Wallet has no account");

  const hash = await walletClient.writeContract({
    address: config.reputationRegistry,
    abi: REPUTATION_REGISTRY_ABI,
    functionName: "giveFeedback",
    args: [
      agentId,
      BigInt(score), // int128
      0,             // uint8 valueDecimals
      tag1,
      tag2,
      "", // endpoint — unused for now
      feedbackURI,
      feedbackHash,
    ],
    account: walletClient.account,
    chain: walletClient.chain,
  });

  return hash;
}
